#include <stdio.h>
int singleNonDuplicate(int* arr, int arrSize) {
    for (int i = 0; i < arrSize; i++) {
        if (i == 0) {
            if (arr[i] != arr[i + 1])
                return arr[i];
        } else if (i == arrSize - 1) {
            if (arr[i] != arr[i - 1])
                return arr[i];
        } else {
            if (arr[i] != arr[i - 1] && arr[i] != arr[i + 1])
                return arr[i];
        }
    }
    return -1;
}

int main() {
    int arr[] = {1, 1, 2, 2, 3, 3, 4, 5, 5, 6, 6};
    int arrSize = sizeof(arr) / sizeof(arr[0]);
    printf("The single element is: %d\n", singleNonDuplicate(arr, arrSize));
    return 0;
}

